import Foundation
import CoreData

extension ShareEntity {
    @nonobjc nonisolated public class func fetchRequest() -> NSFetchRequest<ShareEntity> {
        return NSFetchRequest<ShareEntity>(entityName: "ShareEntity")
    }

    @NSManaged public var id: UUID
    @NSManaged public var token: String
    @NSManaged public var createdAt: Date
    @NSManaged public var expiresAt: Date
    @NSManaged public var isRevoked: Bool

    // v2: CloudKit sharing fields
    @NSManaged public var inviterUserId: String?
    @NSManaged public var participantUserId: String?
    @NSManaged public var status: String?
    @NSManaged public var acceptedAt: Date?
    @NSManaged public var revokedAt: Date?
    @NSManaged public var cloudKitShareRecordName: String?
    @NSManaged public var cloudKitRootRecordName: String?
    @NSManaged public var cloudKitShareURL: String?
    @NSManaged public var role: String?

    // Relationships
    @NSManaged public var souvenir: SouvenirEntity?
}

extension ShareEntity: Identifiable {}

extension ShareEntity {
    /// Check if this share is currently valid (not expired and not revoked)
    public var isValid: Bool {
        return !isRevoked && expiresAt > Date()
    }

    /// Time remaining until expiration (nil if already expired)
    public var timeRemaining: TimeInterval? {
        let remaining = expiresAt.timeIntervalSinceNow
        return remaining > 0 ? remaining : nil
    }

    /// Revoke this share token
    public func revoke() {
        isRevoked = true
    }
}
